import os, psycopg2, uuid
url = os.environ['DATABASE_URL'].replace('postgresql+asyncpg://','postgresql://').split('?')[0]
conn = psycopg2.connect(url, sslmode='require')
conn.autocommit = True
cur = conn.cursor()

# Get mill_id
cur.execute("SELECT id FROM mills LIMIT 1")
row = cur.fetchone()
mill_id = row[0] if row else None
print(f"Mill ID: {mill_id}")

